Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/ApplicationPartiesList/ApplicationParty[./Value = " + ApplicationParties.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/ApplicationPartiesList/ApplicationParty[./Description = " + ApplicationParties.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.transformToDisplay:
var description = Services.getValue( REF_DATA_XPATH + "/ApplicationPartiesList/ApplicationParty[./Value = " + ApplicationParties.dataBinding + "]/Description" );
if (description != null)
{
	return description;
}
else
{
	return value;
}

Javascript.miscCode:
ApplicationParties.componentName =	"Application Parties";
ApplicationParties.srcData = 		REF_DATA_XPATH + "/ApplicationPartiesList";
ApplicationParties.rowXPath = 		"ApplicationParty";
ApplicationParties.keyXPath =		"Value";

function ApplicationPartiesLOVButton() {};
ApplicationPartiesLOVButton.tabIndex = __tabIdx++;

function ApplicationPartiesLOVGrid() {};
ApplicationPartiesLOVGrid.dataBinding = ApplicationParties.dataBinding;
ApplicationPartiesLOVGrid.srcData = REF_DATA_XPATH + "/ApplicationPartiesList";
ApplicationPartiesLOVGrid.rowXPath = "ApplicationParty";
ApplicationPartiesLOVGrid.keyXPath = "Value";
ApplicationPartiesLOVGrid.columns = [
	{xpath: "Value"},
	{xpath: "Description"}
];

ApplicationPartiesLOVGrid.raise = {
	eventBinding: {
		singleClicks: [ {element: "ApplicationPartiesLOVButton"} ],
		keys: [ { key: Key.F6, element: "ApplicationParties" } ]
	}
};
